import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !password) {
      setError('Please fill in all fields');
      return;
    }
    setError('');
    setShowConfirm(true);
  };

  const doLogin = async () => {
    setShowConfirm(false);
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('http://localhost:5000/api/auth/login', {
        email: email,
        password: password,
      });
      const data = response.data;
      localStorage.setItem('token', data.token);
      localStorage.setItem('user', JSON.stringify(data.user));
      if (data.user.role === 'admin') {
        navigate('/admin');
      } else {
        navigate('/home');
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Check email and password.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0, left: 0, right: 0, bottom: 0,
      background: 'linear-gradient(135deg, #fdf6f3, #f9ede8, #f5e0d8)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'DM Sans, sans-serif',
      overflow: 'hidden',
    }}>

      {/* Confirm Modal */}
      {showConfirm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(45,31,31,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '2rem', maxWidth: '380px', width: '90%', textAlign: 'center', boxShadow: '0 20px 60px rgba(0,0,0,0.2)' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🌸</div>
            <h3 style={{ color: '#2d1f1f', marginBottom: '0.5rem', fontSize: '1.2rem' }}>Ready to Sign In?</h3>
            <p style={{ color: '#a08880', fontSize: '0.85rem', marginBottom: '1.5rem' }}>Signing in as {email}</p>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => setShowConfirm(false)} style={{ flex: 1, padding: '11px', background: '#f5e8e3', color: '#a08880', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '600' }}>Cancel</button>
              <button onClick={doLogin} style={{ flex: 2, padding: '11px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '700' }}>Yes, Sign In 🌸</button>
            </div>
          </div>
        </div>
      )}

      {/* Main Card */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '820px', width: '95%', borderRadius: '24px', overflow: 'hidden', boxShadow: '0 25px 70px rgba(201,169,154,0.35)', border: '1px solid #f0ddd7' }}>

        {/* LEFT */}
        <div style={{ background: 'linear-gradient(150deg, #c9a99a, #b8887a, #a0706a)', padding: '3rem 2rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
          <div style={{ fontSize: '2.2rem', marginBottom: '1rem' }}>🌸</div>
          <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '700', marginBottom: '1rem', lineHeight: '1.3' }}>Welcome Back to EventHub!</h2>
          <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.85rem', lineHeight: '1.7', marginBottom: '1.5rem' }}>Discover beautiful events and book tickets effortlessly.</p>
          {[
            { icon: '🎭', text: 'Explore curated events' },
            { icon: '🎫', text: 'Instant ticket booking' },
            { icon: '💝', text: 'Secure payments' },
            { icon: '📅', text: 'Track your bookings' },
          ].map((item, i) => (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
              <div style={{ width: '32px', height: '32px', background: 'rgba(255,255,255,0.2)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem' }}>{item.icon}</div>
              <span style={{ color: 'rgba(255,255,255,0.9)', fontSize: '0.82rem' }}>{item.text}</span>
            </div>
          ))}
          <div style={{ marginTop: '1.5rem', background: 'rgba(255,255,255,0.15)', borderRadius: '10px', padding: '10px 14px' }}>
            <p style={{ color: 'white', fontSize: '0.76rem', margin: 0 }}>👑 <strong>Admin?</strong> Use your admin email to access the admin panel.</p>
          </div>
        </div>

        {/* RIGHT */}
        <div style={{ background: '#fffaf8', padding: '3rem 2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>

          {/* Logo */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1.8rem' }}>
            <div style={{ width: '32px', height: '32px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>🌸</div>
            <span style={{ fontWeight: '700', fontSize: '1.1rem', color: '#2d1f1f' }}>Event<span style={{ color: '#c9a99a' }}>Hub</span></span>
          </div>

          <h1 style={{ color: '#2d1f1f', fontSize: '1.6rem', fontWeight: '700', marginBottom: '0.3rem' }}>Sign In</h1>
          <p style={{ color: '#a08880', fontSize: '0.83rem', marginBottom: '1.6rem' }}>Welcome back! 🌷</p>

          {error && (
            <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '10px 13px', borderRadius: '10px', marginBottom: '1.2rem', fontSize: '0.82rem' }}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Email */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>EMAIL ADDRESS</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>✉️</span>
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  required
                  placeholder="you@example.com"
                  style={{ width: '100%', padding: '11px 12px 11px 40px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'}
                  onBlur={e => e.target.style.borderColor = '#f0ddd7'}
                />
              </div>
            </div>

            {/* Password */}
            <div style={{ marginBottom: '1.2rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>🔑</span>
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                  placeholder="Your password"
                  style={{ width: '100%', padding: '11px 12px 11px 40px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'}
                  onBlur={e => e.target.style.borderColor = '#f0ddd7'}
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              style={{ width: '100%', padding: '13px', background: loading ? '#ccc' : 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '10px', fontWeight: '700', fontSize: '0.92rem', cursor: loading ? 'not-allowed' : 'pointer', boxShadow: '0 5px 18px rgba(201,169,154,0.4)' }}
            >
              {loading ? '✨ Signing in...' : '🌸 Sign In'}
            </button>
          </form>

          <p style={{ marginTop: '1.3rem', textAlign: 'center', color: '#a08880', fontSize: '0.82rem' }}>
            Don't have an account?{' '}
            <Link to="/register" style={{ color: '#c9a99a', fontWeight: '700' }}>Create one →</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
